// // This is a 16-to-4 decoder that takes a 16-bit binary input and activates one of the 4 output lines based on the input value.
module decoder4to16(  
    input [3:0] A,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        Y = 16'b0;  
        Y[A] = 1'b1;  
    end  
endmodule
